utilities.cssRaw:
.mt16 { margin-top: 16rem !important; }
@media screen and (max-width: 768px) {
  .mt16 { margin-top: 8rem !important; }
}
@media screen and (max-width: 414px) {
  .mt16 { margin-top: 5rem !important; }
}

.mb16 { margin-bottom: 16rem !important; }
@media screen and (max-width: 768px) {
  .mb16 { margin-bottom: 8rem !important; }
}
@media screen and (max-width: 414px) {
  .mb16 { margin-bottom: 5rem !important; }
}

.spbr { display: none; }
@media screen and (max-width: 768px) {
  .spbr { display: block; }
}

.pcbr { display: block; }
@media screen and (max-width: 768px) {
  .pcbr { display: none; }
}

.pc_none { display: none; }
@media screen and (max-width: 768px) {
  .pc_none { display: inherit; }
}

@media screen and (max-width: 768px) {
  .sp_nowrap { display: flex; }
  .sp_nowrap .w10 { width: 10%; }
  .sp_nowrap .w20 { width: 20%; }
  .sp_nowrap .w30 { width: 30%; }
  .sp_nowrap .w40 { width: 40%; }
  .sp_nowrap .w50 { width: 50%; }
  .sp_nowrap .w60 { width: 60%; }
  .sp_nowrap .w70 { width: 70%; }
  .sp_nowrap .w80 { width: 80%; }
  .sp_nowrap .w90 { width: 90%; }
}

.googlemap { padding-bottom: 45%; margin: var(--px50) auto; }
@media print, screen and (max-width: 768px) {
  .googlemap { padding-bottom: 80%; }
}

.youtubeArea {
  position: relative;
  overflow: hidden;
  margin: var(--px50) auto;
}
.youtubeArea::before {
  content: '';
  display: block;
  padding-top: 56.25%;
}
.youtubeArea > iframe {
  position: absolute;
  width: 100%;
  height: 100%;
  top: 0;
  left: 0;
}

.fw_contents { margin-top: 0; margin-bottom: 0; }
.fw_contents .page_contents_inner {
  margin-right: calc(((100vw - 100%) / 2) * -1);
  margin-left: calc(((100vw - 100%) / 2) * -1);
  padding: var(--px120) calc((100vw - 100%) / 2) var(--px150);
  margin-top: 0;
}
.fw_contents .page_contents_inner:nth-child(even) { background: #f5f5f5; }

.read_txt {
  font-size: var(--rem18);
  text-align: center;
  letter-spacing: .1rem;
  line-height: 2.2;
  margin: var(--px60) auto var(--px80);
}

.post .col2_list {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
}
.post .col2_list > li {
  width: 49%;
  margin-bottom: 2%;
}
@media screen and (max-width: 414px) {
  .post .col2_list > li { width: 100%; }
  .post .col2_list > li:last-child { margin-bottom: 0; }
}

.post .col3_list {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
}
.post .col3_list > li {
  width: 32%;
  margin-bottom: 2%;
}
.post .col3_list::before, .post .col3_list::after {
  content: '';
  display: block;
  width: 32%;
  height: 0;
}
.post .col3_list::before { order: 1; }
@media screen and (max-width: 768px) {
  .post .col3_list > li { width: 49%; }
  .post .col3_list::before, .post .col3_list::after { content: none; }
}
@media screen and (max-width: 414px) {
  .post .col3_list > li { width: 100%; }
  .post .col3_list > li:last-child { margin-bottom: 0; }
}

.post .col4_list {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
}
.post .col4_list > li {
  width: 24%;
  margin-bottom: 1.5%;
}
.post .col4_list::before, .post .col4_list::after {
  content: '';
  display: block;
  width: 24%;
  height: 0;
}
.post .col4_list::before { order: 1; }
@media screen and (max-width: 1240px) {
  .post .col4_list > li,
  .post .col4_list::before,
  .post .col4_list::after { width: 32%; margin-bottom: 2%; }
}
@media screen and (max-width: 768px) {
  .post .col4_list > li { width: 49%; }
  .post .col4_list::before, .post .col4_list::after { content: none; }
}
@media screen and (max-width: 414px) {
  .post .col4_list > li { width: 100%; }
  .post .col4_list > li:last-child { margin-bottom: 0; }
}

